position: relative;
	overflow: hidden;
	display: block;

	& > * {
		display: block;
		width: 100%;
		height: 100%;
		object-fit: cover;
	}

	&[data-effect='clip'] {
		&.reveal--hidden > * { clip-path: var(--reveal-clip-from); }
		&.reveal--ready > * { will-change: clip-path; }
		&.reveal--visible > * { clip-path: inset(0% 0% 0% 0%); transition: clip-path var(--reveal-duration, 800ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms); }
		&.reveal--leaving > * { clip-path: var(--reveal-clip-from); transition: clip-path var(--reveal-duration, 800ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms); }
		&[data-direction='up'].reveal--hidden > *, &[data-direction='up'].reveal--leaving > * { --reveal-clip-from: inset(100% 0% 0% 0%); }
		&[data-direction='down'].reveal--hidden > *, &[data-direction='down'].reveal--leaving > * { --reveal-clip-from: inset(0% 0% 100% 0%); }
		&[data-direction='left'].reveal--hidden > *, &[data-direction='left'].reveal--leaving > * { --reveal-clip-from: inset(0% 100% 0% 0%); }
		&[data-direction='right'].reveal--hidden > *, &[data-direction='right'].reveal--leaving > * { --reveal-clip-from: inset(0% 0% 0% 100%); }
	}

	&[data-effect='slide'] {
		&.reveal--hidden > * { transform: var(--reveal-slide-from); }
		&.reveal--ready > * { will-change: transform; }
		&.reveal--visible > * { transform: translate(0, 0); transition: transform var(--reveal-duration, 800ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms); }
		&.reveal--leaving > * { transform: var(--reveal-slide-from); transition: transform var(--reveal-duration, 800ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms); }
		&[data-direction='up'].reveal--hidden > *, &[data-direction='up'].reveal--leaving > * { --reveal-slide-from: translateY(105%); }
		&[data-direction='down'].reveal--hidden > *, &[data-direction='down'].reveal--leaving > * { --reveal-slide-from: translateY(-105%); }
		&[data-direction='left'].reveal--hidden > *, &[data-direction='left'].reveal--leaving > * { --reveal-slide-from: translateX(105%); }
		&[data-direction='right'].reveal--hidden > *, &[data-direction='right'].reveal--leaving > * { --reveal-slide-from: translateX(-105%); }
	}

	&[data-effect='fade'] {
		&.reveal--hidden > * { opacity: 0; }
		&.reveal--ready > * { will-change: opacity; }
		&.reveal--visible > * { opacity: 1; transition: opacity var(--reveal-duration, 800ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms); }
		&.reveal--leaving > * { opacity: 0; transition: opacity var(--reveal-duration, 800ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms); }
	}

	&[data-effect='scale'] {
		&.reveal--hidden > * { opacity: 0; transform: var(--reveal-scale-from, scale(1.12)); }
		&.reveal--ready > * { will-change: transform, opacity; }
		&.reveal--visible > * { opacity: 1; transform: scale(1); transition: transform var(--reveal-duration, 800ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms), opacity var(--reveal-duration, 800ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms); }
		&.reveal--leaving > * { opacity: 0; transform: var(--reveal-scale-from, scale(1.12)); transition: transform var(--reveal-duration, 800ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms), opacity var(--reveal-duration, 800ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms); }
		&[data-direction='up'].reveal--hidden > *, &[data-direction='up'].reveal--leaving > * { --reveal-scale-from: scale(1.12); }
		&[data-direction='down'].reveal--hidden > *, &[data-direction='down'].reveal--leaving > * { --reveal-scale-from: scale(0.88); }
	}

	&[data-effect='blur'] {
		&.reveal--hidden > * { opacity: 0; filter: blur(var(--reveal-blur-amount, 16px)); transform: scale(1.04); }
		&.reveal--ready > * { will-change: filter, opacity, transform; }
		&.reveal--visible > * { opacity: 1; filter: blur(0px); transform: scale(1); transition: filter var(--reveal-duration, 800ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms), opacity var(--reveal-duration, 800ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms), transform var(--reveal-duration, 800ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms); }
		&.reveal--leaving > * { opacity: 0; filter: blur(var(--reveal-blur-amount, 16px)); transform: scale(1.04); transition: filter var(--reveal-duration, 800ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms), opacity var(--reveal-duration, 800ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms), transform var(--reveal-duration, 800ms) var(--reveal-easing, ease) var(--reveal-delay, 0ms); }
	}

	&.reveal--done > * { will-change: auto; }
